import os
import psycopg2
from psycopg2 import pool
from typing import Optional

def get_db_connection():
    """
    Create and return a PostgreSQL database connection.
    Credentials are loaded from environment variables for security.
    """
    db_host = os.environ.get('DB_HOST', 'localhost')
    db_port = os.environ.get('DB_PORT', '5432')
    db_name = os.environ.get('DB_NAME', 'hackathon_db')
    db_user = os.environ.get('DB_USER', 'admin')
    db_password = os.environ.get('DB_PASSWORD')
    
    if not db_password:
        raise ValueError("DB_PASSWORD environment variable must be set")
    
    try:
        connection = psycopg2.connect(
            host=db_host,
            port=db_port,
            database=db_name,
            user=db_user,
            password=db_password
        )
        return connection
    except psycopg2.Error as e:
        raise Exception(f"Database connection failed: {e}")


class DatabaseConnectionPool:
    """
    Connection pool manager for PostgreSQL database.
    """
    _pool: Optional[pool.SimpleConnectionPool] = None
    
    @classmethod
    def initialize_pool(cls, minconn=1, maxconn=10):
        """Initialize the connection pool"""
        db_host = os.environ.get('DB_HOST', 'localhost')
        db_port = os.environ.get('DB_PORT', '5432')
        db_name = os.environ.get('DB_NAME', 'hackathon_db')
        db_user = os.environ.get('DB_USER', 'admin')
        db_password = os.environ.get('DB_PASSWORD')
        
        if not db_password:
            raise ValueError("DB_PASSWORD environment variable must be set")
        
        try:
            cls._pool = pool.SimpleConnectionPool(
                minconn,
                maxconn,
                host=db_host,
                port=db_port,
                database=db_name,
                user=db_user,
                password=db_password
            )
        except psycopg2.Error as e:
            raise Exception(f"Connection pool initialization failed: {e}")
    
    @classmethod
    def get_connection(cls):
        """Get a connection from the pool"""
        if cls._pool is None:
            cls.initialize_pool()
        return cls._pool.getconn()
    
    @classmethod
    def return_connection(cls, connection):
        """Return a connection to the pool"""
        if cls._pool:
            cls._pool.putconn(connection)
    
    @classmethod
    def close_all_connections(cls):
        """Close all connections in the pool"""
        if cls._pool:
            cls._pool.closeall()


if __name__ == "__main__":
    conn = get_db_connection()
    cursor = conn.cursor()
